<script setup lang="ts">
import{ref,onMounted}from'vue';import{authApi}from'../../api/auth';import{saveSession,session}from'../../stores/session';import AuthField from'../../components/AuthField.vue'
const uni={navigateTo:(options:any)=>wx.navigateTo(options),reLaunch:(options:any)=>wx.redirectTo(options),showToast:(options:any)=>wx.showToast(options)}
const username=ref(''),password=ref(''),captchaCode=ref(''),captchaId=ref(''),captchaImage=ref(''),loading=ref(false),agreed=ref(false),showPassword=ref(false)
async function loadCaptcha(){try{const data=await authApi.captcha();captchaId.value=data.captchaId;captchaImage.value=data.imageBase64.startsWith('data:')?data.imageBase64:`data:image/png;base64,${data.imageBase64}`}catch{captchaImage.value=''}}
async function login(){if(!username.value||!password.value||!captchaCode.value){uni.showToast({title:'请完整填写登录信息',icon:'none'});return}if(!agreed.value){uni.showToast({title:'请先同意用户协议和隐私政策',icon:'none'});return}loading.value=true;try{const data=await authApi.login({username:username.value.trim(),password:password.value,captchaId:captchaId.value,captchaCode:captchaCode.value.trim()});if(data.role!=='patient'&&data.role!=='admin')throw new Error('当前账号不是患者账号');saveSession({...data,currentPatientId:data.patients?.find(item=>item.isPrimary===1)?.patientId||data.patients?.[0]?.patientId||null});uni.reLaunch({url:'/pages/home/index'})}catch(error){captchaCode.value='';await loadCaptcha();uni.showToast({title:error instanceof Error?error.message:'登录失败',icon:'none'})}finally{loading.value=false}}
onMounted(()=>{if(session.token)setTimeout(()=>wx.redirectTo({url:'/pages/home/index'}),50);else loadCaptcha()})
</script>
<template><view class="auth-page login-page"><image class="hero-bg" src="/static/auth/hospital-hero.png" mode="aspectFill"/><view class="brand"><view class="brand-mark"><text>♡</text><view class="pulse"/></view><view><text class="brand-name">熙康云医院</text><text class="brand-desc">患者端 · 让医疗和护理服务到家</text></view></view><view class="login-card"><view class="heading"><text>欢迎登录</text><view class="safe">◆ 安全登录，保护隐私</view></view><text class="subtitle">请输入您的账号信息</text><text class="label">账号</text><AuthField v-model="username" icon="○" placeholder="请输入用户名" compact/><text class="label">密码</text><AuthField v-model="password" icon="▣" :password="!showPassword" placeholder="请输入密码" compact><text class="eye" @tap="showPassword=!showPassword">{{showPassword?'隐':'◡'}}</text></AuthField><text class="label">验证码</text><view class="captcha-row"><AuthField v-model="captchaCode" icon="◇" placeholder="请输入验证码" compact/><image v-if="captchaImage" :src="captchaImage" mode="aspectFit" @tap="loadCaptcha"/><view v-else class="captcha-empty" @tap="loadCaptcha">点击获取</view><text class="refresh" @tap="loadCaptcha">↻ 换一张</text></view><view class="agreement" @tap="agreed=!agreed"><text :class="{checked:agreed}">{{agreed?'✓':''}}</text><view>我已阅读并同意 <b>《用户服务协议》</b> 和 <b>《隐私政策》</b></view></view><button class="primary-btn" :loading="loading" @tap="login">登录</button></view><view class="register-link"><text>还没有账号？</text><text @tap="uni.navigateTo({url:'/pages/register/index'})">立即注册 ◉</text></view><view class="bottom-wave"><view/><view/><text>+</text></view></view></template>
<style scoped lang="scss">.auth-page{position:relative;min-height:100vh;overflow:hidden;background:#f7fbff;color:#102e61}.hero-bg{position:absolute;left:0;top:0;width:100%;height:520rpx;opacity:.74}.brand{position:relative;z-index:1;padding:calc(var(--status-bar-height) + 145rpx) 66rpx 70rpx;display:flex;align-items:center;gap:22rpx}.brand-mark{position:relative;width:98rpx;height:98rpx;border-radius:25rpx;display:flex;align-items:center;justify-content:center;background:linear-gradient(145deg,#2388ff,#2469f5);box-shadow:0 12rpx 25rpx rgba(29,112,235,.22);color:#fff}.brand-mark>text{font-size:72rpx;line-height:1}.pulse{position:absolute;width:30rpx;height:4rpx;background:#fff;transform:rotate(-25deg)}.brand-name,.brand-desc{display:block}.brand-name{font-size:39rpx;font-weight:700;letter-spacing:1rpx}.brand-desc{margin-top:10rpx;color:#517099;font-size:20rpx}.login-card{position:relative;z-index:2;margin:0 42rpx;padding:42rpx 43rpx 45rpx;border-radius:34rpx;background:rgba(255,255,255,.97);box-shadow:0 18rpx 55rpx rgba(40,94,164,.16)}.heading{display:flex;align-items:center;gap:16rpx}.heading>text{font-size:34rpx;font-weight:700}.safe{color:#8697b2;font-size:19rpx}.safe::first-letter{color:#2878ff}.subtitle{display:block;margin:12rpx 0 28rpx;color:#8b99ad;font-size:21rpx}.label{display:block;margin:21rpx 0 10rpx;color:#173b72;font-size:21rpx;font-weight:600}.eye{padding-left:10rpx;color:#5279b8;font-size:20rpx}.captcha-row{display:grid;grid-template-columns:1fr 155rpx 105rpx;gap:10rpx;align-items:center}.captcha-row image,.captcha-empty{width:155rpx;height:82rpx;border:1rpx solid #e1e9f4;border-radius:16rpx;background:#fff}.captcha-empty{display:flex;align-items:center;justify-content:center;color:#2878ff;font-size:18rpx}.refresh{color:#4b78b7;font-size:19rpx}.agreement{display:flex;align-items:flex-start;gap:10rpx;margin:25rpx 0;color:#7e8ca3;font-size:18rpx;line-height:1.55}.agreement>text{width:27rpx;height:27rpx;flex:none;border:2rpx solid #aebdd0;border-radius: